const updateAutonomyState = `-- name: UpdateAutonomyState :execrows
UPDATE autonomy_state
SET level = ?, consecutive_approvals = ?, updated_at = ?
WHERE tool = ? AND class = ? AND scope = ?
`

type UpdateAutonomyStateParams struct {
	Level                int64  `json:"level"`
	ConsecutiveApprovals int64  `json:"consecutive_approvals"`
	UpdatedAt            string `json:"updated_at"`
	Tool                 string `json:"tool"`
	Class                string `json:"class"`
	Scope                string `json:"scope"`
}

// Update-half of an application-level upsert (kahyad/internal/policy
// calls this first; a 0-rows-affected result means no row exists yet, so
// it falls back to InsertAutonomyState - the same "upsert (update half)"
// pattern UpdateEpisodeContent above already uses in this file).
func (q *Queries) UpdateAutonomyState(ctx context.Context, arg UpdateAutonomyStateParams) (int64, error) {
	result, err := q.db.ExecContext(ctx, updateAutonomyState,
		arg.Level,
		arg.ConsecutiveApprovals,
		arg.UpdatedAt,
		arg.Tool,
		arg.Class,
		arg.Scope,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected()
}

const updateEpisodeContent = `-- name: UpdateEpisodeContent :exec
UPDATE episodes
SET source_hash = ?, source_tier = ?, status = ?
WHERE id = ?
`

type UpdateEpisodeContentParams struct {
	SourceHash sql.NullString `json:"source_hash"`
	SourceTier string         `json:"source_tier"`
	Status     string         `json:"status"`
	ID         int64          `json:"id"`
}

// Upserts (update half) an existing memory_file episode in place on
// new/changed content: same id, fresh hash/tier, status forced back to
// 'active' (covers the resurrect-a-deleted-file case, not just plain edits).
func (q *Queries) UpdateEpisodeContent(ctx context.Context, arg UpdateEpisodeContentParams) error {
	_, err := q.db.ExecContext(ctx, updateEpisodeContent,
		arg.SourceHash,
		arg.SourceTier,
		arg.Status,
		arg.ID,
	)
	return err
}

const updateTaskSession = `-- name: UpdateTaskSession :exec
UPDATE tasks
SET session_id = ?, updated_at = ?
WHERE id = ?
`

type UpdateTaskSessionParams struct {
	SessionID sql.NullString `json:"session_id"`
	UpdatedAt string         `json:"updated_at"`
	ID        string         `json:"id"`
}

// Persists a worker-reported session_id onto the task row (W12-07 step 3:
// kahyad "persists session_id onto the task row" as the worker's
// {"type":"session",...} stdout line arrives). Session RESUME itself
// (using a stored session_id to continue a LATER task) is W4-02; this
// query only records the value as it arrives.
func (q *Queries) UpdateTaskSession(ctx context.Context, arg UpdateTaskSessionParams) error {
	_, err := q.db.ExecContext(ctx, updateTaskSession, arg.SessionID, arg.UpdatedAt, arg.ID)
	return err
}

